import React from 'react';
import styled from 'styled-components';
import { device } from './@media';
import GlobalFonts from './5fonts/Fonts';
import {BrowserRouter, Routes, Route } from "react-router-dom";

import Wrapper from './wrapper.jsx';
import Nav from './3nav/nav.jsx';
import Header from './2header/header.jsx';
import Main from './4main/main.jsx';

const SApp = styled.div`
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 55px); 
background: green ;
color: black ;
font-family: 'TopSecretWoff2' ;

@media ${device.mobileM} { 
border: solid 0.2px blue;
font-family: 'TopSecretWoff2' ;
}
`


function App() {
  return (
<BrowserRouter>
<SApp >
<GlobalFonts/>

<Routes>
<Route path='/' element={<Wrapper/>}>
<Route path='index' element={<Header/>}/>
<Route path='index' element={<Nav/>}/>
<Route path='index' element={<Main/>}/>
</Route>
</Routes>

</SApp>
</BrowserRouter>
  );
};



export default App;
//npm start
